def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        base_score = 0
        if ratio < 0.1:
            base_score = np.cos(ratio * 15) * (1 - ratio)**2 + 0.1 * ratio**-0.5
        elif 0.1 <= ratio < 0.3:
            base_score = np.log1p(ratio * 10) * 3 - ratio * 4 + np.sqrt(ratio)
        elif 0.3 <= ratio < 0.6:
            base_score = np.tanh(12 * (ratio - 0.45)) + np.exp(-5 * (ratio - 0.45)**2)
        elif 0.6 <= ratio < 0.85:
            base_score = np.arcsin(min(1, ratio)) + np.cos(ratio * 12) / (ratio + 0.3)
        else:
            base_score = (1 / (1 + np.exp(-40 * (ratio - 0.9)))) + 0.4 * np.sin(ratio * 25)
        penalty = 0
        for j in range(1, 10):
            mod_val = (item * j**2) % capacity
            frac = mod_val / (capacity * (j + np.sqrt(ratio)))
            if frac < 0.03:
                penalty += frac * (5 - j * 0.3)
            elif 0.03 <= frac < 0.15:
                penalty += frac * (2 + j * 0.1)
            elif 0.15 <= frac < 0.4:
                penalty += frac * (1 - (j * 0.05))
            else:
                penalty += frac / ((j + ratio + 1)**1.5)
        extra_penalty = 0
        threshold = 0.25
        for k in range(1, 7):
            if ratio > threshold:
                val = np.exp(-k * ratio) * (k**2) * np.cos(k * ratio * 3)
                extra_penalty += val if val < 1 else 1
            else:
                log_val = np.log1p(k**3 * ratio + k**2)
                extra_penalty += (log_val / (k + 3)) * np.sqrt(ratio + 0.1)
            threshold += 0.15
        complexity_factor = 0
        for m in range(1, 5):
            for n in range(1, 5):
                combined = (ratio * m + n / 2) % 1
                if combined < 0.2:
                    complexity_factor += np.sin(combined * 4 * np.pi) / (m * n) + np.log1p(m + n)
                elif 0.2 <= combined < 0.6:
                    complexity_factor += (np.cos(combined * 6 * np.pi) / (m + n)) * (ratio + 0.1)
                else:
                    complexity_factor += (combined ** 3) / (m * n + 1) + np.sqrt(m * n)
        mod_capacity = capacity % 7
        if mod_capacity == 0:
            priority_score = base_score + penalty * 0.75 + extra_penalty * 1.1 + complexity_factor * 0.85
        elif mod_capacity in {1, 3, 5}:
            priority_score = base_score + penalty * 1.3 + extra_penalty * 0.5 + complexity_factor * 1.2
        elif mod_capacity in {2, 4, 6}:
            priority_score = base_score + penalty * 1.0 + extra_penalty * 0.9 + complexity_factor * 0.65
        else:
            priority_score = base_score + penalty + extra_penalty + complexity_factor
        if capacity > 100:
            priority_score *= np.log1p(capacity / 50)
        if np.isclose(priority_score, np.inf):
            priority_score = 1e10
        if priority_score < 0:
            priority_score = 0
        if ratio > 0.5:
            secondary_factor = 0
            for x in range(1, 4):
                for y in range(1, 4):
                    val = np.tanh(ratio * x / (y + 1)) * np.sin(capacity / (x + y + 1))
                    if val > 0.5:
                        secondary_factor += val * (x + y) / 5
                    else:
                        secondary_factor -= val / (x + y + 1)
            priority_score += secondary_factor
        priorities[i] = priority_score
    return priorities
